import React from "react"
import { graphql } from "gatsby"
import yaml from "js-yaml"
import Layout from "../../components/Layout"
import DateShareTitle from "../../components/DateShareTitle"
import { formatDate, dateOffset } from "../../util"
import Link from "../../components/IntlLink"
import FA from "../../components/FA"
import { getString } from "../../util"

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function PageTemplate({ pageContext: { language }, data: { meta, mdx, members } }) {

	const cx = classNames.bind(styles);

	const metadata = meta.siteMetadata.collections.filter(c => c.collection === mdx.fields.collection)[0]

	function getAuthor(author, j, mod=false) {
		let name
		let org
		let slug = ""
		const tmp = members.nodes.filter(x => (x.frontmatter.memberid === author.name || (author.name && author.name.en && x.frontmatter.memberid === author.name.en)) && x.fields.lang === language)
		if (tmp.length > 0) {
			name = tmp[0].frontmatter.title
			org = tmp[0].frontmatter.org
			slug = tmp[0].fields.originalPath
		}
		else {
			name = getString(author.name, language)
		}
		
		// override affiliations
		if (author.org)
			org = getString(author.org, language)

		if (!name) {
			console.error(author)
			console.log(name)
			return <React.Fragment>???</React.Fragment>
		}

		name = name.split(' ').map((x, i) =>
			<React.Fragment key={`$name${i}`}><span className="nobreak">{x}</span> </React.Fragment>
		)

		if (mod) {
			return(
				<React.Fragment>
					{name} ({org})
				</React.Fragment>
			)
		}
		else {
			return(
				<div className={cx("author")} key={`author${j}`}>
					<div className={cx("name")} data-typesense-field="body"><Link to={slug}>{name}</Link></div>
					<div className={cx("org")} data-typesense-field="body">
						{org}
						<Links data={author} />
					</div>
				</div>
			)
		}
	}

	function getGroup(g, i) {
		let o
		let p
		if ('group' in g) {
			// regular
			o = g.group
			p = g.people
		}
		else {
			let key = Object.keys(g)[0]
			p = g[key]
			if (["author", "discussant", "panelist", "moderator", "mod"].includes(key))
				key += "s"
			const xxx = {
				by: {th: "โดย", en: "by"},
				authors: {th: "ผู้เขียน", en: "Author"},
				discussants: {th: "ผู้วิจารณ์", en: "Discussant"},
				panelists: {th: "ผู้เสวนา", en: "Panelist"},
				moderators: {th: "ผู้ดำเนินการเสวนา", en: "Moderator"},
				mods: {th: "ประธาน", en: "Moderator"},
			}
			o = xxx[key]
			if (p.length > 1) {
				o.en += "s"
			}
		}
		return(
			<div className={cx("peopleGroup", {notime: mdx.frontmatter.notime})} key={`group${i}`}>
				<div>{getString(o, language)}</div>
				<div>{p.map((author, j) => getAuthor(author, j))}</div>
			</div>
		)
	}

	function getFile(f) {
		return mdx.frontmatter.files.filter(fileObject => fileObject.base === f)[0].publicURL
	}

	function Links({ data }) {
		return(
			<React.Fragment>
				<div className={cx("links")}>
					{data.doc &&
						<a href={getFile(getString(data.doc, language))} target="_blank" rel="nofollow noopener noreferrer" className="left-margin"><FA icon="page" alt="Document" /></a>
					}
					{data.slides &&
						<a href={getFile(getString(data.slides, language))} target="_blank" rel="nofollow noopener noreferrer" className="left-margin"><FA icon="slide" alt="Presentation" /></a>
					}
					{data.video &&
						<a href={data.video} target="_blank" rel="nofollow noopener noreferrer" className="left-margin"><FA icon="youtube" alt="Video" /></a>
					}
				</div>
			</React.Fragment>
		)
	}

	function Event({ event }) {
		// if (!event.peopleGroup) {
		// 	console.error('No peopleGroup: ', event)
		// }
		if (event.details)
			console.log(event.details)
		return(
			<tr>
				{!mdx.frontmatter.notime && <td className={cx("time")}>{event.time}</td>}
				<td className={cx("event")}>
					<div className={cx("title", {notime: mdx.frontmatter.notime})} data-typesense-field="body">
						{getString(event.title, language)}
						<Links data={event} />
					</div>
					{event.details &&
						<div>
							{typeof event.details === "string" &&
								<p>{event.details.split("\n").map(line => <React.Fragment>{line}<br /></React.Fragment>)}</p>
							}
							{typeof event.details === "array" &&
								event.details.map(d => <p>{d.split("\n").map(line => <React.Fragment>{line}<br /></React.Fragment>)}</p>)
							}
						</div>
					}
					{event.peopleGroup &&
						event.peopleGroup.map((group, i) => getGroup(group, i))
					}
				</td>
			</tr>
		)
	}

	function EventGroup({ events }) {
		return(
			<tbody>
				{events.map((event, i) => {
					if (event.type === "event") {
						return(
							<Event event={event} key={`event${i}`}/>
						)
					}
					else if (event.type === "part") {
						return(
							<tr className={cx("partRow")} key={`event${i}`}>
								<td colSpan="2" className={cx("part")}>
									<div className={cx("partTitle")}>
										<div className={cx("partTop")}>
											<div className={cx("partText")} data-typesense-field="body">{getString(event.name || event.title, language)}</div>
											{event.mod &&
												<div className={cx("mod")} data-typesense-field="body">
													{language === "th" ? "ประธาน :" : "Moderator: "} {getAuthor(event.mod, 0, true)}
												</div>
											}
											{event.details &&
												<div className={cx("details")} data-typesense-field="body">{getString(event.details, language)}</div>
											}
										</div>
										<Links data={event} />
									</div>
									<table className={cx("partTable")}>
										<EventGroup events={event.events} />
									</table>
								</td>
							</tr>
						)
					}
					else {
						let o
						if (event.type === "misc") {
							o = event.title
						}
						else {
							const xxx = {
								registration: {th: "ลงทะเบียน", en: "Registration"},
								break: {th: "พักรับประทานอาหารว่าง", en: "Break"},
								lunch: {th: "พักรับประทานอาหารกลางวัน", en: "Lunch break"},
							}
							o = xxx[event.type]
						}	
						return(
							<tr key={`event${i}`}>
								<td className={cx("time")}>{event.time}</td>
								<td>{getString(o, language)}</td>
							</tr>
						)
					}
				})}
			</tbody>
		)
	}

	return(
		<Layout
			lang={language}
			mdx={mdx}
			metadata={metadata}
			showCover={true}
		>
			<DateShareTitle
				frontmatter={mdx.frontmatter}
				lang={language}
			/>
			{
				mdx.frontmatter.data.map((day_data, i) => {
					const events = yaml.load(day_data)
					return(
						<React.Fragment key={`day${i}`}>
							<div className={cx("mainTable")} key={`$events${i}`}>
								{mdx.frontmatter.data.length > 1 && <h4>{formatDate(dateOffset(mdx.frontmatter.date, i), language)}</h4>}
								<table>
									<EventGroup events={events} />
								</table>
							</div>
							{mdx.frontmatter.endnote &&
								<div className={cx("endnote")}>{mdx.frontmatter.endnote}</div>
							}
						</React.Fragment>
					)
				})
			}
		</Layout>
	)
}

export const pageQuery = graphql`
	query ConferenceQuery($id: String) {
		meta: site {
			siteMetadata {
				collections {
					collection
					title
					subtitle
					url
					placeholder
				}
			}
		}
		mdx(id: { eq: $id }) {
			frontmatter {
        date
				date_end
        title
        location
				files {
          base
          publicURL
        }
				data
				notime
				endnote
				cover {
					publicURL
					childImageSharp {
						gatsbyImageData(layout: FULL_WIDTH)
						thumbnail: gatsbyImageData(layout: CONSTRAINED, width: 160, height: 160)
					}
				}
      }
      fields {
				collection
        slug
				shorturl
      }
		}
		members: allMdx(filter: {fields: {collection: {eq: "members"}}}) {
			nodes {
				frontmatter {
					memberid
					org
					title
				}
				fields {
					lang
					originalPath
				}
			}
		}
	}
`